export function getWordsByChapter(wordIds: string[]): Word[] {
  return wordIds.map(id => words[id] || pdfWords[id]).filter(Boolean);
}

export function getWordById(id: string): Word | undefined {
  return words[id] || pdfWords[id];
}

export function getAllWords(): Word[] {
  return Object.values(words);
}
